mapper.select:
SELECT ID, CONTACT_NO,
PARENT_ID, CUSTOMER_ID, CUSTOMER_NAME, SIGN_TIME, CONTRACT_TYPE, IS_SHIP, SETTLEMENT_BASIS_CODE, SETTLEMENT_BASIS_NAME,EXP_SETTLEMENT_BASIS_CODE, EXP_SETTLEMENT_BASIS_NAME,OUTER_SETTLEMENT_BASIS_CODE, OUTER_SETTLEMENT_BASIS_NAME,LUXIAO_SETTLEMENT_BASIS_CODE, LUXIAO_SETTLEMENT_BASIS_NAME, DEPOSIT_BASIS_CODE, DEPOSIT_BASIS_NAME, DEPOSIT_RATIO, PAY_TYPE, FREE_STORAGE_DAYS, START_TIME, END_TIME, SHIPVOYAGE_ID, VALID_BY, VALID_BY_NAME, VALID_TIME, STATUS, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_BUS_CONTRACT
id = #{id}

SELECT COUNT(0)
FROM T_COST_STORAGE_SETTLE
WHERE CONTRACT_ID = #{contractId, jdbcType=BIGINT}

SELECT TBR.ID, TBR.RATE_ITEM_CODE, TBR.RATE_ITEM_NAME, TBR.SERVICE_CONTENT_ID, TBR.SERVICE_CONTENT_NAME, TBR.PROCESS_CODE, TBR.PROCESS_NAME, TBR.CARGO_CODE, TBR.CARGO_NAME || (CASE WHEN (MC.SIGN IS NOT NULL OR MC.SIGN != '') THEN ('(' || MC.SIGN || ')') END ) "CARGO_NAME", TBR.INTE_FORE, TBR.RATE, TBR.TAX_RATE, TBR.MEASUREMENT_UNIT_CODE1, MDD.DICT_LABEL MEASUREMENT_UNIT_NAME1, TBR.MEASUREMENT_UNIT_CODE2, TBR.STATUS, TBR.START_DATE, TBR.END_DATE, TBR.REMARK, TBR.EXAMINE_BY, TBR.EXAMINE_BY_NAME, TBR.EXAMINE_TIME, TBR.CREATE_BY, TBR.CREATE_BY_NAME, TBR.CREATE_TIME, TBR.UPDATE_BY, TBR.UPDATE_BY_NAME, TBR.UPDATE_TIME, TBR.FREE_STORAGE_DAYS, DECODE(TBS.IN_OUT, 'IN', '进口', 'OUT', '出口') IMP_EXP FROM T_BUS_RATE TBR JOIN M_CARGO MC ON TBR.CARGO_CODE = MC.CARGO_CODE LEFT JOIN M_DICT_DATA MDD ON MDD.DICT_TYPE = 'UNIT' AND TBR.MEASUREMENT_UNIT_CODE1 = MDD.DICT_VALUE JOIN T_BUS_SERVICE TBS ON TBR.SERVICE_CONTENT_ID = TBS.ID WHERE TBR.STATUS = '10' AND (#{startTime,jdbcType=TIMESTAMP} >= START_DATE AND #{startTime,jdbcType=TIMESTAMP} <= END_DATE) AND TBR.RATE_ITEM_NAME = '港口作业包干费' AND TBR.CARGO_CODE IN
#{cargoCode, jdbcType=VARCHAR}
ORDER BY TBR.INTE_FORE, TBS.IN_OUT, TBR.SERVICE_CONTENT_NAME
